/**
 * @param {number} n
 * @param {number[]} prices
 * @param {number[][]} roads
 * @return {number[]}
 */
function solve(n, prices, roads) {
    // Adjacency list for the graph. Since roads are bidirectional, we store edges for both directions.
    // Each entry: [neighbor, cost_no_apple, cost_with_apple]
    const adj = Array(n).fill(0).map(() => []);

    for (const [u, v, cost, tax] of roads) {
        // Edge u -> v
        // Cost without apple: cost
        // Cost with apple: cost * tax
        adj[u].push({ neighbor: v, cost_no_apple: cost, cost_with_apple: cost * tax });
        // Edge v -> u (bidirectional)
        adj[v].push({ neighbor: u, cost_no_apple: cost, cost_with_apple: cost * tax });
    }

    /**
     * Dijkstra's algorithm implementation.
     * @param {number} startNode - The starting node for the path.
     * @param {boolean} is_carrying_apple - True if the path is taken while carrying apples, false otherwise.
     * @returns {number[]} - Array of minimum distances from startNode to all other nodes.
     */
    const dijkstra = (startNode, is_carrying_apple) => {
        // Initialize distances to infinity
        const dist = Array(n).fill(Number.MAX_SAFE_INTEGER);
        dist[startNode] = 0;

        // Min-heap: stores [distance, node]
        const pq = [[0, startNode]];

        while (pq.length > 0) {
            // Simple priority queue implementation: sort and pop minimum
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > dist[u]) continue;

            for (const edge of adj[u]) {
                const v = edge.neighbor;
                let travel_cost;

                if (is_carrying_apple) {
                    travel_cost = edge.cost_with_apple;
                } else {
                    travel_cost = edge.cost_no_apple;
                }

                const newDist = dist[u] + travel_cost;

                if (newDist < dist[v]) {
                    dist[v] = newDist;
                    pq.push([newDist, v]);
                }
            }
        }
        return dist;
    };

    // 1. Calculate shortest paths without carrying apples (Outbound travel: Empty hand -> Store j)
    // dist_empty[j] = min cost to reach store j with no apples from any starting store i.
    // Wait, we need to calculate this for every possible starting store i, because the empty-hand trip starts at i.
    // Let D_empty[i][j] be the minimum cost to travel from i to j without apples.
    const D_empty = Array(n).fill(0).map(() => Array(n).fill(0));
    for (let i = 0; i < n; i++) {
        // Run Dijkstra starting from i, assuming empty hands (is_carrying_apple = false)
        const dists = dijkstra(i, false);
        for (let j = 0; j < n; j++) {
            D_empty[i][j] = dists[j];
        }
    }

    // 2. Calculate shortest paths with carrying apples (Return travel: Store j -> Store i)
    // Let D_full[j][i] be the minimum cost to travel from j to i while carrying apples.
    const D_full = Array(n).fill(0).map(() => Array(n).fill(0));
    for (let j = 0; j < n; j++) {
        // Run Dijkstra starting from j, assuming full hands (is_carrying_apple = true)
        const dists = dijkstra(j, true);
        for (let i = 0; i < n; i++) {
            D_full[j][i] = dists[i];
        }
    }

    const ans = Array(n).fill(0);

    // For each destination store i (where we buy the apple)
    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at i
        let min_cost = prices[i];

        // Option 2: Travel from i (empty) -> j (buy) -> i (full)
        for (let j = 0; j < n; j++) {
            if (i === j) continue;

            // Cost = (Empty i -> j) + prices[j] + (Full j -> i)
            const cost_empty_to_j = D_empty[i][j];
            const cost_full_j_to_i = D_full[j][i];

            // Check if paths exist (should always exist if graph is connected, but safer check)
            if (cost_empty_to_j !== Number.MAX_SAFE_INTEGER && cost_full_j_to_i !== Number.MAX_SAFE_INTEGER) {
                const total_cost = cost_empty_to_j + prices[j] + cost_full_j_to_i;
                min_cost = Math.min(min_cost, total_cost);
            }
        }
        ans[i] = min_cost;
    }

    return ans;
}

