    // Edge structure: [neighbor, cost_no_apple, cost_with_apple]
    // Using a mutable array of mutable lists for the adjacency list
    val adj: Array[mutable.List[(Int, Long, Long)]] = Array.fill(n)(mutable.List())

    for (road in roads) {
      val u = road(0).toInt
      val v = road(1).toInt
      val cost = road(2)
      val tax = road(3)

      val costWithApple = cost * tax

      // Edge u -> v (bidirectional)
      adj(u) += ((v, cost, costWithApple))
      // Edge v -> u (bidirectional)
      adj(v) += ((u, cost, costWithApple))
    }

    /**
     * Dijkstra's algorithm implementation.
     * @param startNode The starting node for the path.
     * @param isCarryingApple True if the path is taken while carrying apples, false otherwise.
     * @return Array of minimum distances from startNode to all other nodes.
     */
    def dijkstra(startNode: Int, isCarryingApple: Boolean): Array[Long] = {
      // Initialize distances to infinity
      val dist: Array[Long] = Array.fill(n)(MaxValue)
      dist(startNode) = 0L

      // Min-heap (using Scala's sorted structure for simplicity, though a proper heap implementation would be faster)
      val pq = mutable.PriorityQueue[State]()
      pq.add(State(0L, startNode))

      while (!pq.isEmpty()) {
        val (d, u) = pq.poll()

        if (d > dist(u)) continue

        for ((v, costNoApple, costWithApple) <- adj(u)) {
          var travelCost: Long = 0L

          if (isCarryingApple) {
            travelCost = costWithApple
          } else {
            travelCost = costNoApple
          }

          val newDist = dist(u) + travelCost

          if (newDist < dist(v)) {
            dist(v) = newDist
            pq.add(State(newDist, v))
          }
        }
      }
      dist
    }

    // 1. Calculate shortest paths without carrying apples (Outbound travel: Empty hand -> Store j)
    // D_empty[i][j] = min cost to travel from i to j without apples.
    val dEmpty: Array[Array[Long]] = Array.fill(n)(Array.fill(n)(0L))
    for (i <- 0 until n) {
      val dists = dijkstra(i, false)
      for (j <- 0 until n) {
        dEmpty(i)(j) = dists(j)
      }
    }

    // 2. Calculate shortest paths with carrying apples (Return travel: Store j -> Store i)
    // D_full[j][i] = min cost to travel from j to i while carrying apples.
    val dFull: Array[Array[Long]] = Array.fill(n)(Array.fill(n)(0L))
    for (j <- 0 until n) {
      val dists = dijkstra(j, true)
      for (i <- 0 until n) {
        dFull(j)(i) = dists(i)
      }
    }

    val ans: Array[Long] = Array.fill(n)(0L)

    // For each destination store i (where we buy the apple)
    for (i <- 0 until n) {
      // Option 1: Buy directly at i
      var minCost: Long = prices(i)

      // Option 2: Travel from i (empty) -> j (buy) -> i (full)
      for (j <- 0 until n) {
        if (i == j) continue

        // Cost = (Empty i -> j) + prices[j] + (Full j -> i)
        val costEmptyToJ = dEmpty(i)(j)
        val costFullJToI = dFull(j)(i)

        // Check if paths exist
        if (costEmptyToJ != MaxValue && costFullJToI != MaxValue) {
          // We must ensure that the sum does not overflow Long, though given constraints (N=1000, cost*tax ~ 10^11)
          // standard Long (up to 9*10^18) should suffice.
          val totalCost = costEmptyToJ + prices(j) + costFullJToI
          if (totalCost < minCost) {
            minCost = totalCost
          }
        }
      }
      ans(i) = minCost
    }

    ans
  }
