import scala.collection.mutable
import scala.math.Long.MaxValue

object Solution {
  /**
    * @param n The number of stores.
    * @param prices Array of prices at each store.
    * @param roads Array of road connections: [u, v, cost, tax].
    * @return Array of minimum total costs for each store.
    */
  def solve(n: Int, prices: Array[Long], roads: Array[Array[Long]]): Array[Long] = {
    // Edge structure: (neighbor, cost_no_apple, cost_with_apple)
    type Edge = (Int, Long, Long)
    val adj: Array[mutable.List[Edge]] = Array.fill(n)(mutable.ListBuffer.empty[Edge])

    for (road in roads) {
      val u = road(0).toInt
      val v = road(1).toInt
      val cost = road(2)
      val tax = road(3)

      // Cost with apple = cost * tax
      val costWithApple = cost * tax

      // Edge u -> v
      adj(u) += (v, cost, costWithApple)
      // Edge v -> u (bidirectional)
      adj(v) += (u, cost, costWithApple)
    }

    /**
     * Dijkstra's algorithm implementation.
     * @param startNode The starting node.
     * @param isCarryingApple True if the path is taken while carrying apples, false otherwise.
     * @return Array of minimum distances from startNode to all other nodes.
     */
    def dijkstra(startNode: Int, isCarryingApple: Boolean): Array[Long] = {
      // Initialize distances to infinity
      val dist: Array[Long] = Array.fill(n)(MaxValue)
      dist(startNode) = 0

      // Min-heap: stores (distance, node). Using a mutable priority queue structure is complex in standard Scala collections, 
      // so we'll use a simpler approach (like the JS reference, sorting a list) or a manual PQ implementation.
      // For N <= 1000, O(N^2) or slightly worse complexity from list sorting might pass, but a proper heap is better.
      // We use a list and sort it repeatedly, similar to the JS reference logic.
      var pq: mutable.List[(Long, Int)] = mutable.List( (0, startNode) )

      while (pq.nonEmpty) {
        // Sort and pop minimum (inefficient but mimics JS reference)
        pq = pq.sortBy(_._1).toSeq.toMutable()
        val (d, u) = pq.remove(0)

        if (d > dist(u)) continue

        for ((v, costNoApple, costWithApple) <- adj(u)) {
          var travelCost: Long = if (isCarryingApple) costWithApple else costNoApple

          val newDist = dist(u) + travelCost

          if (newDist < dist(v)) {
            dist(v) = newDist
            pq += (newDist, v)
          }
        }
      }
      dist
    }

    // 1. Calculate shortest paths without carrying apples (Empty hand -> Store j)
    // D_empty[i][j] = min cost to travel from i to j without apples.
    val DEmpty: Array[Array[Long]] = Array.fill(n)(Array.fill(n)(MaxValue))
    for (i <- 0 until n) {
      val dists = dijkstra(i, false)
      for (j <- 0 until n) {
        DEmpty(i)(j) = dists(j)
      }
    }

    // 2. Calculate shortest paths with carrying apples (Store j -> Store i)
    // D_full[j][i] = min cost to travel from j to i while carrying apples.
    val DFull: Array[Array[Long]] = Array.fill(n)(Array.fill(n)(MaxValue))
    for (j <- 0 until n) {
      val dists = dijkstra(j, true)
      for (i <- 0 until n) {
        DFull(j)(i) = dists(i)
      }
    }

    val ans: Array[Long] = Array.fill(n)(0)

    // For each destination store i (where we want to buy the apple)
    for (i <- 0 until n) {
      // Option 1: Buy directly at i
      var minCost: Long = prices(i)

      // Option 2: Travel from i (empty) -> j (buy) -> i (full)
